import java.sql.*; //We need this for our JDBC classes and interfaces, e.g., Connection etc...
//To protect against sql injection attacks you can avoid directly including user input in SQL queries or parametrizing them using PreparedStatements if possible (Depending on your use case). However, as we only focus here is the concept of how it could be done: https://stackoverflow.com/questions/14053276
public class java_46798_JDBCQueryHandler_A08 {  //We name our classes according to their purpose in this context; e.g., ConnectionPooling etc... But I chose 'JDBCDemo' here as per your instructions, just make sure it matches the actual use case!  
    public static void main(String[] args) {    
        String url = "jdbc:mysql://localhost/test"; //This could be any valid URL depending on where and how you connect to MySQL database. Change this accordingly if necessary - e.g., If your host is not localhost or test, change them as well!  https://dev.mysql.com/doc/refman/8.0/en/connector-j/connector-j/connection-url.html
        String username = "root"; //This could be any valid MySQL user name - e.g., if your root password is 'password', change it as well!  https://dev.mysql.com/doc/refman/8.0/en/connector-j/connector-j/connection-url.html
        String password = "root"; //This could be any valid MySQL user's Password - e.g., if your root database is 'test', change it as well! https://dev.mysql.com/doc/refman/8.0/en/connector-j/connector-j/connection-url.html
        Connection connection = null; //This will hold our actual SQL connections - e.g., MySQL database connector  object is named 'conn' in this example but it could be different, just make sure the name matches with what you have used when creating a new instance of DriverManager and if necessary change them as well!
        Statement statement = null; //This will hold our SQL statements - e.g., MySQL database connector  object is named 'stmt' in this example but it could be different, just make sure the name matches with what you have used when creating a new instance of Connection and if necessary change them as well!
        try {  
            connection = DriverManager.getConnection(url, username, password); //Create our SQL database connector object  - e.g., MySQL JDBC driver for connecting to the server & providing credentials is named 'conn' in this example but it could be different name used when creating a new instance of Connection and if necessary change them as well!
            statement = connection.createStatement(); //Create our SQL statements executor object - e.g., MySQL JDBC driver for executing queries on server & providing credentials is named 'stmt' in this example but it could be different name used when creating a new instance of Connection and if necessary change them as well!
            ResultSet resultset = statement.executeQuery("SELECT * FROM employees"); //Execute our SQL query - e.g., Select all records from the "employees" table  https://dev.mysql.com/doc/refman/8.0/en/sql-statement-data-retrieval.html
            while (resultset.next()) {    //Iterate through every field in ResultSet - e.g., Print out all employee information when SELECT statement is executed  https://dev.mysql.com/doc/refman/8.0/en/sql-statement-data-retrieval.html
                System.out.println(resultset.getString("firstName")); //Print the first name from each row in ResultSet - e.g., Print out employee's names  https://dev.mysql.com/doc/refman/8.0/en/sql-statement-data-retrieval.html
            }     
        } catch (SQLException se) { //Catch any SQL exception that might occur when executing our query and print out the error message - e.g., If there's a problem with MySQL server, it will be caught here  https://docs.oracle.com/javase/tutorial/jdbc/basics/catchingexceptions.html
            se.printStackTrace();   //Print our exception stack trace for debugging purposes - e.g., This prints out the current state of any issues that might have occurred when executing MySQL query in Java  https://docs.oracle.com/javase/tutorial/jdbc/basics/catchingexceptions.html
        } finally { //Always ensure our database connection is closed after we're done with it - e.g., If there were any issues when executing the MySQL query, this will always close the statement and release resources used by a Connection  https://docs.oracle.com/javase/tutorial/jdbc/basics/close.html
            if (statement != null) {    //Ensure our Statement is not closed in case an exception occurs - e.g., If there's any issue, it will be caught here and close the statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/close.html
                try {    //Try to execute our Statement   (This won’t work if an exception occurred in above code) - e.g., If there's any issue, it will be caught here and closed the statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/close.html
                    //Any additional operations should go inside this try-catch block to ensure our resource is safely released (Closing Statement in case of exception, Connection being dropped) - e.g., If there's any issue with closing the connection or statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/close.html
                    //Ensure our database connections are closed after we have finished using them to avoid memory leaks and provide a clean state for JVM at shutdown (closing Connection in case of exception)  https://docs.oracle.com/javase/tutorial/jdbc/basics/close.html
                    statement.close();   //This will always ensure our Statement is not closed if there were any issues when executing MySQL query - e.g., If the SQL operation was unsuccessful, this would close it  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
                } catch (SQLException se2) {   //Handle any error that might occur while closing our Statement - e.g., If there's a problem with MySQL server, it will be caught here and print out the message  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
                    se2.printStackTrace();   //This prints our exception stack trace for debugging purposes - e.g., If there's a problem with MySQL server, it will be caught here and print out the message  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
                }   //Ensure our database connections are closed after we have finished using them to avoid memory leaks (Closing Connection in case of exception) - e.g., If there's any issue with closing the connection or statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
            }   //Ensure our database connections are closed after we have finished using them to avoid memory leaks and provide a clean state for JVM at shutdown (Closing Connection in case of exception) - e.g., If there's any issue with closing the connection or statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
        }   //Ensure our database connections are closed after we have finished using them to avoid memory leaks and provide a clean state for JVM at shutdown (Closing Connection in case of exception) - e.g., If there's any issue with closing the connection or statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
    }   //Ensure our database connections are closed after we have finished using them to avoid memory leaks and provide a clean state for JVM at shutdown (Closing Connection in case of exception) - e.g., If there's any issue with closing the connection or statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html
}   //Ensure our database connections are closed after we have finished using them to avoid memory leaks and provide a clean state for JVM at shutdown (Closing Connection in case of exception) - e.g., If there's any issue with closing the connection or statement  https://docs.oracle.com/javase/tutorial/jdbc/basics/closingstmts.html